  let created = 0
  for (const pd of productsData) {
    const responsibleId = pd.responsibleKey ? userMap[pd.responsibleKey] || null : null
    
    // Calculate progress
    const totalStages = pd.stages.length
    const completedStages = pd.stages.filter((s: any) => s.date && new Date(s.date) < new Date()).length
    const progress = totalStages > 0 ? Math.round((completedStages / totalStages) * 100) : 0
    
    const product = await prisma.product.create({
      data: {
        name: pd.name,
        country: pd.country,
        status: pd.status,
        priority: pd.priority,
        finalDate: pd.finalDate,
        responsibleId,
        progressPercent: progress,
        stages: {
          create: (pd.stages.map((s: any) => {
            const template = stageTemplates.find(t => t.order === s.order)
            if (!template) return null
            
            const stageDate = s.date ? new Date(s.date) : null
            const isOverdue = stageDate && stageDate < new Date() && !s.date
            
            return {
              stageTemplateId: template.id,
              stageOrder: s.order,
              stageName: template.name,
              dateValue: stageDate,
              dateRaw: s.raw || null,
              status: stageDate && stageDate < new Date() ? StageStatus.COMPLETED : StageStatus.NOT_STARTED,
              isCompleted: !!(stageDate && stageDate < new Date()),
              isCritical: template.isCritical,
              affectsFinalDate: template.affectsFinalDate,
              participatesInAutoshift: template.participatesInAutoshift,
              responsibleId,
              plannedDate: stageDate,
            }
          }).filter(Boolean)) as any[]
        }
      }
    })
    created++
    if (created % 10 === 0) console.log(`  📦 Created ${created} products...`)
  }
  
